/* 3. Elastic Jelly Toggle Styles */
.switch-jelly {
  position: relative;
  display: inline-block;
  width: 54px;
  height: 30px;
}

.switch-jelly input {
  opacity: 0; width: 0; height: 0;
}

.slider-jelly {
  position: absolute;
  cursor: pointer;
  top: 0; left: 0; right: 0; bottom: 0;
  background-color: #e2e8f0;
  transition: background-color 0.3s ease;
  border-radius: 30px;
}

.slider-jelly::before {
  content: "";
  position: absolute;
  height: 24px; width: 24px;
  left: 3px; bottom: 3px;
  background-color: white;
  border-radius: 50%;
  transition: transform 0.4s cubic-bezier(0.68, -0.6, 0.27, 1.55), width 0.3s cubic-bezier(0.68, -0.6, 0.27, 1.55);
}

.switch-jelly input:checked + .slider-jelly {
  background-color: #6366f1;
}

.switch-jelly input:checked + .slider-jelly::before {
  transform: translateX(24px);
}

.switch-jelly input:active + .slider-jelly::before {
  width: 32px;
}
